SELECT COALESCE(MAX(resolved), 0)
FROM analysis_quality_flag
WHERE target_type = #{targetType} AND target_id = #{targetId} AND flag_type = #{flagType}

mapper.update:
UPDATE admin_career_run_memo
SET memo_type = #{memoType},
    content = #{content}
WHERE id = #{id}
  AND career_analysis_run_id = #{careerAnalysisRunId}
  AND deleted_at IS NULL
  AND EXISTS (
      SELECT 1
      FROM career_analysis_run active_run
      INNER JOIN users active_user ON active_user.id = active_run.user_id
      WHERE active_run.id = #{careerAnalysisRunId}
        AND active_user.status != 'DELETED'
        AND active_user.deleted_at IS NULL
  )

UPDATE admin_career_run_memo
   SET deleted_at = COALESCE(deleted_at, NOW())
 WHERE id = #{id}
   AND career_analysis_run_id = #{runId}
   AND deleted_at IS NULL
   AND EXISTS (
       SELECT 1
       FROM career_analysis_run active_run
       INNER JOIN users active_user ON active_user.id = active_run.user_id
       WHERE active_run.id = #{runId}
         AND active_user.status != 'DELETED'
         AND active_user.deleted_at IS NULL
   )
